<!doctype html>
<html lang="fr"><head><meta charset="utf-8"><title>Emploi du temps</title><style>body{font-family:DejaVu Sans,sans-serif;color:#172033;font-size:10px}h2{text-align:center;margin:0 0 16px}.info{margin-bottom:14px}.info span{display:inline-block;width:32%;margin:3px 0}table{width:100%;border-collapse:collapse}th,td{border:1px solid #aab4c2;padding:7px;vertical-align:top}thead th{background:#173b78;color:#fff;text-align:center}.time{background:#f4f7fb;text-align:center;width:105px}.break{background:#d1d5db;text-align:center;font-weight:bold;text-transform:uppercase;letter-spacing:1px}.cell{height:45px}</style></head>
<body><h2>EMPLOI DU TEMPS DU PROFESSEUR</h2><div class="info"><span><b>Nom :</b> {{ $enseignant->nom }}</span><span><b>Prénoms :</b> {{ $enseignant->prenoms }}</span><span><b>Matricule :</b> {{ $enseignant->matricule ?? '—' }}</span><span><b>Sexe :</b> {{ $enseignant->sexe ?? '—' }}</span><span><b>Années d’enseignement :</b> {{ $enseignant->nombre_annees_enseignement ?? '—' }}</span><span><b>Discipline(s) :</b> {{ $enseignant->matieres->pluck('nom')->join(', ') }}</span><span><b>Classe(s) :</b> {{ $enseignant->classes->pluck('nom')->join(', ') }}</span><span><b>Série(s) :</b> {{ $enseignant->series->pluck('nom_serie')->join(', ') }}</span></div><table><thead><tr><th>Horaires</th>@foreach($days as $day)<th>{{ ucfirst($day) }}</th>@endforeach</tr></thead><tbody>@foreach($slots as $slot)@if(isset($slot['break']))<tr><td class="break" colspan="6">{{ $slot['break'] }}</td></tr>@else @php($slotKey=$slot[0].'-'.$slot[1])<tr><td class="time">{{ str_replace(':','h',$slot[0]) }} - {{ str_replace(':','h',$slot[1]) }}</td>@foreach($days as $day)@php($entry=$grid[$day][$slotKey]??null)<td class="cell">@if($entry)<b>{{ $entry->matiere?->nom }}</b><br>{{ $entry->classe?->nom }}@if($entry->serie)<br>Série : {{ $entry->serie->nom_serie }}@endif@if($entry->salle)<br>Salle : {{ $entry->salle }}@endif@endif</td>@endforeach</tr>@endif@endforeach</tbody></table></body></html>
